import{_ as o,o as c,c as d,a2 as i}from"./chunks/framework.VshInwhI.js";const _=JSON.parse('{"title":"开发环境规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/02-dev-environment.md","filePath":"mango-pmo/rules/02-dev-environment.md"}'),l={name:"mango-pmo/rules/02-dev-environment.md"};function a(r,e,n,t,s,m){return c(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="开发环境规范" tabindex="-1">开发环境规范 <a class="header-anchor" href="#开发环境规范" aria-label="Permalink to &quot;开发环境规范&quot;">​</a></h1><h2 id="_1-定位" tabindex="-1">1. 定位 <a class="header-anchor" href="#_1-定位" aria-label="Permalink to &quot;1. 定位&quot;">​</a></h2><ul><li>本文件约束 Mango 本地开发环境、工作区配置和前后端启动方式。</li><li>本地开发环境的长期规则只放在 <code>mango-pmo</code>。</li><li>配套脚本放在仓库根目录 <code>scripts/</code>。</li></ul><h2 id="_2-工作区配置" tabindex="-1">2. 工作区配置 <a class="header-anchor" href="#_2-工作区配置" aria-label="Permalink to &quot;2. 工作区配置&quot;">​</a></h2><ul><li>每个工作区必须使用 <code>mango workspace init</code> 初始化本地配置。</li><li><code>scripts/dev-workspace.sh</code> 只保留为历史兼容入口，正式开发、验证和交付命令必须使用 Mango CLI。</li><li>所有代码、接口、数据库、测试、前端页面或构建配置改动必须在任务专用 Git worktree 中进行。</li><li>任务 worktree 必须从最新 <code>main</code> 新建，并使用独立任务分支。</li><li>一个任务或一个 PR 在本地只能对应一个开发 worktree。</li><li>验收返工、Review 修改、CI 修复和 PR 门禁修复必须复用该任务或 PR 的既有 worktree。</li><li>新建 worktree 前，Agent 必须先执行 <code>git worktree list</code>，确认是否已有同一任务分支或 PR 分支对应的 worktree。</li><li>只有新独立任务、用户明确拆分任务、原 worktree 丢失或用户明确要求重建时，才允许创建新的 worktree。</li><li>原 worktree 丢失或损坏时，必须基于原任务分支重建 worktree，不得另起无关联分支。</li><li>主工作区只用于拉取 <code>main</code>、创建 worktree、查看状态和执行清理，不承载任务改动。</li><li>只修改 PMO 规范、流程、Agent 入口、设计文档、Sprint 计划、交付记录或历史材料，且不影响服务代码、接口、数据库、测试、前端页面或构建配置时，可按 preflight 的 <code>main-direct-allowed</code> 结果在主工作区直接提交。</li><li>本地工作区配置文件固定为 <code>.mango/workspace.json</code> 和 <code>.mango/dev-workspace.env</code>。</li><li><code>.mango/workspace.json</code> 记录当前 worktree 的稳定 slot、端口、数据库名和 workspace id，禁止提交到 Git。</li><li><code>.mango/dev-workspace.env</code> 只属于当前工作区，禁止提交到 Git。</li><li>Mango CLI 应维护本机工作区注册表，避免同一台机器上不同 worktree 分配到相同端口或数据库名。</li><li>Mango CLI 首次初始化时按稳定工作区号 <code>NNN</code> 分配端口和数据库名。</li><li>工作区号 <code>NNN</code> 必须同时体现在后端端口、前端端口、子前端端口和数据库名中。</li><li>后端端口固定为 <code>18NNN</code>，前端主端口固定为 <code>30NNN</code>，子前端端口固定为 <code>31NNN</code>、<code>32NNN</code>、<code>33NNN</code> 递增表达子应用类型。</li><li>数据库名固定为 <code>mango_dev_&lt;projectSlug&gt;_&lt;NNN&gt;</code>。</li><li>Mango CLI 分配工作区号时必须跳过本机已监听端口、注册表已占用端口、注册表已占用数据库名，以及本机 MySQL 中已存在的目标 <code>MANGO_DB_NAME</code>。</li><li>已存在 <code>.mango/dev-workspace.env</code> 时，脚本禁止覆盖本机数据库连接、插件开关等人工配置；但 <code>MANGO_WORKSPACE_ID</code>、<code>MANGO_BACKEND_PORT</code>、<code>MANGO_FRONTEND_PORT</code>、子前端端口和 <code>MANGO_DB_NAME</code> 必须同步为 <code>.mango/workspace.json</code> 的当前值。</li><li>同一个工作区必须复用同一组端口和数据库名。</li><li>不同工作区应使用不同的端口和数据库名。</li><li>新工作区首次生成 <code>.mango/dev-workspace.env</code> 时，禁止选择本机已存在的 <code>MANGO_DB_NAME</code>，避免误复用旧库数据。</li><li>新建 Git worktree 后必须执行 <code>mango workspace init</code>。</li></ul><h2 id="_3-必需配置项" tabindex="-1">3. 必需配置项 <a class="header-anchor" href="#_3-必需配置项" aria-label="Permalink to &quot;3. 必需配置项&quot;">​</a></h2><p><code>.mango/workspace.json</code> 至少包含：</p><ul><li><code>workspaceId</code>：当前 worktree 标识。</li><li><code>slot</code>：当前 worktree 的稳定端口槽位。</li><li><code>backendPort</code>：后端端口。</li><li><code>frontendPort</code>：前端主端口。</li><li><code>frontendApps</code>：前端子应用端口映射。</li><li><code>dbName</code>：当前工作区本地数据库名。</li></ul><p><code>.mango/dev-workspace.env</code> 至少包含：</p><ul><li><code>MANGO_BACKEND_PORT</code>：后端本地端口。</li><li><code>MANGO_FRONTEND_PORT</code>：前端本地端口。</li><li><code>MANGO_DB_NAME</code>：当前工作区本地数据库名。</li><li><code>MANGO_DB_HOST</code>：数据库主机。</li><li><code>MANGO_DB_PORT</code>：数据库端口。</li><li><code>MANGO_DB_USERNAME</code>：数据库用户名。</li><li><code>MANGO_DB_PASSWORD</code>：数据库密码。</li><li><code>MANGO_OFFICE_PLUGIN_ENABLED</code>：是否启用本地 Office 转换插件，开发默认 <code>false</code>。</li></ul><h2 id="_4-启动规则" tabindex="-1">4. 启动规则 <a class="header-anchor" href="#_4-启动规则" aria-label="Permalink to &quot;4. 启动规则&quot;">​</a></h2><ul><li>默认使用 <code>mango dev start</code> 启动本地前后端。</li><li>只启动后端使用 <code>mango dev start backend</code>。</li><li>只启动前端使用 <code>mango dev start frontend</code>。</li><li>停止当前工作区服务使用 <code>mango dev stop</code>。</li><li>查看当前工作区配置使用 <code>mango workspace status</code>。</li><li>诊断当前工作区使用 <code>mango dev doctor</code>。</li><li>前端 source 模式准备使用 <code>mango frontend prepare</code>。</li><li>Mango CLI 必须从 <code>.mango/workspace.json</code> 和 <code>.mango/dev-workspace.env</code> 读取端口、数据库名和数据库连接信息。</li><li>开发环境默认关闭 Office 转换插件；需要本地调试文件预览转换时，显式将 <code>MANGO_OFFICE_PLUGIN_ENABLED=true</code> 并配置本机 Office 组件。</li><li>Mango CLI 必须在启动前检查端口占用和工作区归属。</li><li>端口冲突时必须失败并提示占用进程或 owner worktree，禁止静默随机换端口。</li><li>前端 Vite 端口必须由 Mango CLI 注入；前端 app 不得在 <code>dev</code> 脚本中写死本地端口。</li></ul><h2 id="_4-1-cli-版本来源" tabindex="-1">4.1 CLI 版本来源 <a class="header-anchor" href="#_4-1-cli-版本来源" aria-label="Permalink to &quot;4.1 CLI 版本来源&quot;">​</a></h2><ul><li>全局安装的 <code>@mango/cli</code> 只用于创建项目、历史项目升级和跨仓库临时诊断。</li><li>业务项目日常开发、验证和交付命令必须优先使用项目内锁定的 <code>@mango/cli</code>。</li><li>业务项目存在 <code>frontend/package.json</code> 且声明 <code>@mango/cli</code> 时，进入 <code>frontend</code> 后使用 <code>pnpm exec mango ...</code> 执行 <code>mango workspace</code>、<code>mango dev</code> 和 <code>mango frontend</code> 命令。</li><li>系统 <code>PATH</code> 上的 <code>mango</code> 不能作为业务项目 CLI 版本依据，也不能用来判断项目依赖批次是否已升级。</li><li>历史项目缺少项目内 <code>@mango/cli</code> 或兼容脚本时，才允许先用全局 <code>mango pmo upgrade --project-dir . --sync-shell</code> 补齐项目入口，再执行项目内依赖安装和 <code>mango workspace init</code>。</li></ul><h2 id="_4-2-worktree-删除规则" tabindex="-1">4.2 Worktree 删除规则 <a class="header-anchor" href="#_4-2-worktree-删除规则" aria-label="Permalink to &quot;4.2 Worktree 删除规则&quot;">​</a></h2><ul><li>原生 <code>git worktree remove</code> 不负责停止服务，也不负责删除数据库。</li><li>删除开发 worktree 必须先使用 <code>mango dev stop</code> 停止服务，再使用 <code>mango workspace release --workspace &lt;path&gt;</code> 释放本机注册。</li><li>任务 PR 合并前禁止删除对应 worktree，除非用户明确取消该任务或要求重建 worktree。</li><li>PR 合并后必须清理对应 worktree；需要保留本地开发数据库时显式追加 <code>--keep-db</code>。</li><li>删除 worktree 前必须按目标 worktree 的 <code>.mango/workspace.json</code> 和 <code>.mango/dev-workspace.env</code> 停止对应端口上的前后端服务。</li><li><code>mango workspace release --workspace &lt;path&gt;</code> 默认删除当前 workspace 拥有的本地开发数据库。</li><li>只有显式传入 <code>--keep-db</code> 时才允许保留数据库。</li><li>脚本只允许删除 <code>.mango/workspace.json</code> 或本机 workspace 注册表记录中归属于目标 worktree 且名称匹配 <code>mango_dev_*</code> 的本地工作区数据库。</li><li>需要强制移除 dirty worktree 时，必须显式传入 <code>--force</code>。</li></ul><h2 id="_5-数据库规则" tabindex="-1">5. 数据库规则 <a class="header-anchor" href="#_5-数据库规则" aria-label="Permalink to &quot;5. 数据库规则&quot;">​</a></h2><ul><li>本地开发数据库名必须来自 <code>MANGO_DB_NAME</code>。</li><li><code>MANGO_DB_AUTO_CREATE=true</code> 只表示允许 Mango CLI 在启动 Spring Boot app 前创建本地工作区数据库，不表示绕过本机 MySQL 连接前置条件。</li><li>自动创建数据库依赖本机 <code>mysql</code> 命令可用，并且 <code>MANGO_DB_HOST</code>、<code>MANGO_DB_PORT</code>、<code>MANGO_DB_USERNAME</code>、<code>MANGO_DB_PASSWORD</code> 能连接到目标 MySQL。</li><li>Mango CLI 只能自动创建名称匹配 <code>mango_dev_*</code> 的工作区数据库；数据库名不匹配时必须拒绝启动。</li><li>自动建库失败必须在 CLI 输出和应用日志中暴露具体失败原因，禁止继续静默等待 health 超时。</li><li>释放 workspace 时默认删除当前 workspace 拥有的本地开发数据库；保留数据库必须显式传入 <code>--keep-db</code>。</li><li>删除数据库必须执行受控清理命令，且只能删除目标 worktree 记录的、名称匹配 <code>mango_dev_*</code> 的本地工作区数据库。</li><li>数据库结构和初始数据仍由 Flyway migration 管理。</li><li>禁止用本地启动脚本替代正式 migration。</li><li>禁止把本地数据库名写死到应用配置或代码中。</li></ul><h2 id="_6-运行时临时目录" tabindex="-1">6. 运行时临时目录 <a class="header-anchor" href="#_6-运行时临时目录" aria-label="Permalink to &quot;6. 运行时临时目录&quot;">​</a></h2><ul><li>仓库内运行时临时文件统一放到 <code>&lt;repo&gt;/.runtime/</code>。</li><li><code>.runtime/</code> 必须被 Git 忽略，禁止提交。</li><li>测试 <code>mango-cli</code> 生成的新项目必须放到 <code>.runtime/projects/</code>。</li><li>临时包缓存必须放到 <code>.runtime/package-store/</code>。</li><li>临时启动日志、浏览器脚本中间产物、下载文件和非证据截图必须放到 <code>.runtime/</code> 下的子目录。</li><li><code>mango-docs/evidence/</code> 只保存最终验收截图、报告和可复核脚本，禁止放生成项目、依赖缓存、构建产物和运行日志。</li><li>任务结束后应清理 <code>.runtime/</code> 中与本次任务相关且不再需要的内容。</li></ul><h2 id="_7-agent-执行要求" tabindex="-1">7. Agent 执行要求 <a class="header-anchor" href="#_7-agent-执行要求" aria-label="Permalink to &quot;7. Agent 执行要求&quot;">​</a></h2><ul><li>需要启动本地服务时，Agent 必须使用 <code>mango dev start</code>、<code>mango dev start backend</code> 或 <code>mango dev start frontend</code>。</li><li>需要修复验收、Review、CI 或 PR 门禁发现的问题时，Agent 必须先复用当前任务或 PR 的既有 worktree。</li><li>需要删除本地开发 worktree 时，Agent 必须先停止服务并释放 workspace 注册。</li><li>启动前必须说明本次使用的后端端口、前端端口和数据库名。</li><li>启动失败时必须先检查 <code>.mango/workspace.json</code>、<code>.mango/dev-workspace.env</code>、端口归属、数据库连接和启动日志。</li><li>只有调试脚本本身或用户明确要求时，才允许绕过该脚本手写启动命令。</li></ul><h2 id="_8-破坏性升级说明" tabindex="-1">8. 破坏性升级说明 <a class="header-anchor" href="#_8-破坏性升级说明" aria-label="Permalink to &quot;8. 破坏性升级说明&quot;">​</a></h2><ul><li>从本规范生效起，正式本地开发入口从 <code>scripts/dev-workspace.sh</code> 切换为 Mango CLI。</li><li>旧脚本只作为兼容 shim，不再维护端口分配、数据库分配、前端准备或进程归属逻辑。</li><li>业务项目升级后必须执行 <code>mango workspace init</code> 生成 <code>.mango/workspace.json</code>；旧 <code>.mango/dev-workspace.env</code> 会被 CLI 补齐缺失字段。</li><li>旧的 <code>~/.mango/workspaces.tsv</code> 注册表不再作为正式数据源；Mango CLI 使用 <code>~/.mango/workspaces.json</code>。</li><li>如果旧 worktree 已占用端口，新的 CLI 启动会失败并提示 owner，开发者必须停止旧 worktree 或释放注册后重试。</li></ul>',24)])])}const g=o(l,[["render",a]]);export{_ as __pageData,g as default};
